"use client";

// Classification: A — static component layout (no React Aria primitive needed).

import type { ComponentProps } from "react";

import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { cva, cx, type VariantProps } from "@/lib/cva";

function InputGroup({ className, ...props }: ComponentProps<"div">) {
    return (
        <div
            className={cx(
                "group/input-group relative flex h-9 w-full min-w-0 items-center rounded-md border border-input shadow-xs transition-[color,box-shadow] outline-none has-[>textarea]:h-auto dark:bg-input/30",
                "has-[>[data-align=inline-start]]:[&>input]:pl-2",
                "has-[>[data-align=inline-end]]:[&>input]:pr-2",
                "has-[>[data-align=block-start]]:h-auto has-[>[data-align=block-start]]:flex-col has-[>[data-align=block-start]]:[&>input]:pb-3",
                "has-[>[data-align=block-end]]:h-auto has-[>[data-align=block-end]]:flex-col has-[>[data-align=block-end]]:[&>input]:pt-3",
                "has-[[data-slot=input-group-control]:focus-visible]:border-ring has-[[data-slot=input-group-control]:focus-visible]:ring-[3px] has-[[data-slot=input-group-control]:focus-visible]:ring-ring/50",
                "has-[[data-slot][aria-invalid=true]]:border-destructive has-[[data-slot][aria-invalid=true]]:ring-destructive/20 dark:has-[[data-slot][aria-invalid=true]]:ring-destructive/40",
                className,
            )}
            data-slot="input-group"
            role="group"
            {...props}
        />
    );
}

let inputGroupAddonVariants = cva({
    base: "flex h-auto cursor-text items-center justify-center gap-2 py-1.5 text-sm font-medium text-muted-foreground select-none group-data-[disabled=true]/input-group:opacity-50 [&>kbd]:rounded-[calc(var(--radius)-5px)] [&>svg:not([class*='size-'])]:size-4",
    variants: {
        align: {
            "inline-start": "order-first pl-3 has-[>button]:ml-[-0.45rem] has-[>kbd]:ml-[-0.35rem]",
            "inline-end": "order-last pr-3 has-[>button]:mr-[-0.45rem] has-[>kbd]:mr-[-0.35rem]",
            "block-start":
                "order-first w-full justify-start px-3 pt-3 group-has-[>input]/input-group:pt-2.5 [.border-b]:pb-3",
            "block-end":
                "order-last w-full justify-start px-3 pb-3 group-has-[>input]/input-group:pb-2.5 [.border-t]:pt-3",
        },
    },
    defaultVariants: {
        align: "inline-start",
    },
});

interface InputGroupAddonProps
    extends ComponentProps<"div">, VariantProps<typeof inputGroupAddonVariants> {}

function InputGroupAddon({ className, align = "inline-start", ...props }: InputGroupAddonProps) {
    return (
        <div
            className={inputGroupAddonVariants({ align, className })}
            data-align={align}
            data-slot="input-group-addon"
            onClick={event => {
                if ((event.target as HTMLElement).closest("button")) {
                    return;
                }

                event.currentTarget.parentElement?.querySelector("input")?.focus();
            }}
            role="group"
            {...props}
        />
    );
}

let inputGroupButtonVariants = cva({
    base: "flex items-center gap-2 text-sm shadow-none",
    variants: {
        size: {
            xs: "h-6 gap-1 rounded-[calc(var(--radius)-5px)] px-2 has-[>svg]:px-2 [&>svg:not([class*='size-'])]:size-3.5",
            sm: "h-8 gap-1.5 rounded-md px-2.5 has-[>svg]:px-2.5",
            "icon-xs": "size-6 rounded-[calc(var(--radius)-5px)] p-0 has-[>svg]:p-0",
            "icon-sm": "size-8 p-0 has-[>svg]:p-0",
        },
    },
    defaultVariants: {
        size: "xs",
    },
});

interface InputGroupButtonProps
    extends
        Omit<ComponentProps<typeof Button>, "className" | "size">,
        VariantProps<typeof inputGroupButtonVariants> {
    className?: string;
}

function InputGroupButton({
    className,
    type = "button",
    variant = "ghost",
    size = "xs",
    ...props
}: InputGroupButtonProps) {
    return (
        <Button
            className={inputGroupButtonVariants({ size, className })}
            data-size={size}
            type={type}
            variant={variant}
            {...props}
        />
    );
}

function InputGroupText({ className, ...props }: ComponentProps<"span">) {
    return (
        <span
            className={cx(
                "flex items-center gap-2 text-sm text-muted-foreground [&_svg]:pointer-events-none [&_svg:not([class*='size-'])]:size-4",
                className,
            )}
            data-slot="input-group-text"
            {...props}
        />
    );
}

function InputGroupInput({ className, ...props }: ComponentProps<"input">) {
    return (
        <Input
            className={cx(
                "flex-1 rounded-none border-0 bg-transparent shadow-none focus-visible:ring-0 dark:bg-transparent",
                className,
            )}
            data-slot="input-group-control"
            {...props}
        />
    );
}

function InputGroupTextarea({ className, ...props }: ComponentProps<"textarea">) {
    return (
        <Textarea
            className={cx(
                "flex-1 resize-none rounded-none border-0 bg-transparent py-3 shadow-none focus-visible:ring-0 dark:bg-transparent",
                className,
            )}
            data-slot="input-group-control"
            {...props}
        />
    );
}

export {
    InputGroup,
    InputGroupAddon,
    InputGroupButton,
    InputGroupText,
    InputGroupInput,
    InputGroupTextarea,
};
